INSERT INTO public.cards (topic_set_id, order_index, question, answer) VALUES
('11111111-1111-1111-1111-111111111111', 26, 'What is Direct Digital Control (DDC)?', 'A control system where a digital computer or microcontroller directly adjusts the control variables (e.g., valve position, motor speed) based on sensor feedback, without intermediate analog devices.'),
('11111111-1111-1111-1111-111111111111', 27, 'Define a Programmable Logic Controller (PLC).', 'A ruggedized industrial digital computer designed for real-time control of manufacturing processes, assembly lines, or robotic devices, using ladder logic or other programming languages.'),
('11111111-1111-1111-1111-111111111111', 28, 'What is a Modem?', 'A device that converts digital data from a computer into analog signals for transmission over communication lines (e.g., telephone lines) and demodulates incoming analog signals back to digital data.'),
('11111111-1111-1111-1111-111111111111', 29, 'Define SCADA.', 'Supervisory Control and Data Acquisition. A high-level system for monitoring and controlling industrial processes across large geographical areas, collecting real-time data from remote sensors and allowing operator intervention.'),
('11111111-1111-1111-1111-111111111111', 30, 'What is a Distributed Control System (DCS)?', 'A control system where control elements are distributed throughout a plant rather than centralized, with local controllers communicating over a network for process automation.'),
('11111111-1111-1111-1111-111111111111', 31, 'Define an Actuator.', 'A device that converts a control signal into physical action (linear or rotary motion), such as a motor, solenoid, or pneumatic cylinder.'),
('11111111-1111-1111-1111-111111111111', 32, 'Explain Pulse Width Modulation (PWM).', 'A technique for controlling analog circuits by varying the duty cycle of a digital square wave, effectively adjusting average voltage or power to a load.'),
('11111111-1111-1111-1111-111111111111', 33, 'What are Protocols in the context of industrial automation?', 'Formal sets of rules and conventions governing data exchange between devices in a communication network (e.g., Modbus, Profibus, Ethernet/IP).'),
('11111111-1111-1111-1111-111111111111', 34, 'Define a Transducer.', 'A device that converts one form of energy to another, often converting a physical quantity (pressure, temperature) into an electrical signal.'),
('11111111-1111-1111-1111-111111111111', 35, 'What is a Sensor?', 'A device that detects or measures a physical property (light, temperature, position) and converts it into an output signal that can be read by an instrument or control system.'),
('11111111-1111-1111-1111-111111111111', 36, 'What is the Setpoint in a control system?', 'The desired value of the controlled variable. The control system aims to minimize the error between the setpoint and the actual measured value.'),
('11111111-1111-1111-1111-111111111111', 37, 'Define a Feedback signal in control systems.', 'The measured actual value of the controlled variable, typically from a sensor. It is compared to the setpoint to generate an error signal.'),
('11111111-1111-1111-1111-111111111111', 38, 'What is a Disturbance input in control systems?', 'An unwanted external influence that affects the system''s output. The control system must reject disturbances to maintain desired performance.'),
('11111111-1111-1111-1111-111111111111', 39, 'List the basic components of a robot.', '1. Manipulator (arm) - the mechanical structure with links and joints. 2. End effector (gripper/tool) - device for interacting with environment. 3. Actuators - motors or hydraulic cylinders. 4. Sensors - provide feedback on position, velocity, force. 5. Controller - processes data and generates commands. 6. Power supply - provides electrical, pneumatic, or hydraulic energy.'),
('11111111-1111-1111-1111-111111111111', 40, 'Describe a Potentiometer as a sensor.', 'Measures angular or linear position by changing resistance. Simple and low-cost but subject to wear. Used in joint angle measurement in robotic systems.'),
('11111111-1111-1111-1111-111111111111', 41, 'What is an Optical encoder?', 'Provides digital position feedback using a rotating disk with slots and a light source/detector. Can be incremental (relative) or absolute. Used for precise motor shaft position measurement.'),
('11111111-1111-1111-1111-111111111111', 42, 'Explain an Ultrasonic sensor.', 'Emits sound waves and measures time-of-flight for echoes to determine distance to objects. Used for obstacle avoidance and navigation in robotic systems.'),
('11111111-1111-1111-1111-111111111111', 43, 'How does an Infrared (IR) sensor work?', 'Uses IR light reflection to detect nearby objects. Some types measure distance via triangulation. Common in line-following and proximity detection applications.'),
('11111111-1111-1111-1111-111111111111', 44, 'What is a Force/torque sensor?', 'Measures forces and moments applied to the robot''s wrist or end effector. Essential for assembly, grinding, and delicate handling tasks.'),
('11111111-1111-1111-1111-111111111111', 45, 'Describe a Vision camera in robotics.', 'Captures images for object recognition, tracking, quality inspection, and visual servoing. Provides rich environmental data. Can be CMOS or CCD type.'),
('11111111-1111-1111-1111-111111111111', 46, 'What is an Inertial Measurement Unit (IMU)?', 'Combines accelerometers and gyroscopes (and sometimes magnetometers) to measure orientation, angular velocity, and linear acceleration. Used for balance in mobile robots.'),
('11111111-1111-1111-1111-111111111111', 47, 'What is a Supercomputer?', 'A computer with extremely high processing power and speed, used for complex scientific simulations, weather forecasting, and quantum mechanics calculations.'),
('11111111-1111-1111-1111-111111111111', 48, 'Define Hardware in computing.', 'The physical, tangible components of a computer system including CPU, RAM, hard drive, and motherboard.'),
('11111111-1111-1111-1111-111111111111', 49, 'Define Software in computing.', 'A set of instructions, data, or programs used to operate computers and execute specific tasks such as operating systems, compilers, and applications.'),
('11111111-1111-1111-1111-111111111111', 50, 'What is a Control System?', 'A system that manages, commands, directs, or regulates the behavior of other devices or systems to achieve a desired output.'),
('11111111-1111-1111-1111-111111111111', 51, 'Define a Passive Transducer.', 'A transducer that requires an external power source to operate. It produces an output signal (e.g., resistance, capacitance) that is a function of the measurand.'),
('11111111-1111-1111-1111-111111111111', 52, 'State the Nyquist Stability Criterion.', 'A closed-loop system is stable if and only if the number of counter-clockwise encirclements of the critical point (-1, 0) by the Nyquist plot of the open-loop transfer function G(s)H(s) equals the number of open-loop poles in the right-half s-plane.'),
('11111111-1111-1111-1111-111111111111', 53, 'What is Maximum Overshoot (Mp) in a second-order system?', 'The maximum amount the response overshoots the final steady-state value, expressed as a percentage.'),
('11111111-1111-1111-1111-111111111111', 54, 'Define Settling Time (Ts) in control systems.', 'The time required for the response to reach and stay within a certain percentage (usually 2% or 5%) of its final value.'),
('11111111-1111-1111-1111-111111111111', 55, 'Explain Cascade Control.', 'A control strategy where the output of one controller (master) serves as the setpoint for another controller (slave). Improves dynamic response and rejects disturbances.'),
('11111111-1111-1111-1111-111111111111', 56, 'What is Ratio Control?', 'A control strategy used to maintain the ratio of two process variables (e.g., flow rates A and B) at a specified value. One flow is the wild stream, and the other is controlled.'),
('11111111-1111-1111-1111-111111111111', 57, 'Define an Activator in control systems.', 'A device that initiates or triggers a process or action within a system. An actuator is a type of activator that moves or controls a mechanism.'),
('11111111-1111-1111-1111-111111111111', 58, 'What are the Laplace Transforms of basic functions?', 'Unit impulse δ(t) → 1; Unit step u(t) → 1/s; Ramp t → 1/s²; Exponential e^(-at) → 1/(s+a); Sine sin(ωt) → ω/(s²+ω²); Cosine cos(ωt) → s/(s²+ω²).'),
('11111111-1111-1111-1111-111111111111', 59, 'State the Laplace Transform of a derivative.', 'The Laplace Transform of f''(t) is sF(s) - f(0).'),
('11111111-1111-1111-1111-111111111111', 60, 'State the Laplace Transform of a second derivative.', 'The Laplace Transform of f''''(t) is s²F(s) - sf(0) - f''(0).'),
('11111111-1111-1111-1111-111111111111', 61, 'Define a Pneumatic Volume Booster.', 'A device used to increase the flow capacity of a pneumatic control system, providing higher volume of air to large actuators without sacrificing response speed.'),
('11111111-1111-1111-1111-111111111111', 62, 'Explain the operation principle of a pneumatic volume booster.', 'It uses a diaphragm assembly with two poppets (one supply, one exhaust). When input pressure rises, it opens the supply poppet allowing high-pressure air to flow. Feedback maintains balance, providing large flow capacity while maintaining 1:1 pressure ratio.'),
('11111111-1111-1111-1111-111111111111', 63, 'What is the transfer function of an inverting operational amplifier with RC circuit?', 'For input impedance Z₁ = R₁ + 1/(sC₁) and feedback impedance Z₂ = R₂/(1 + sR₂C₂), the transfer function is Vo(s)/Vi(s) = -sR₂C₁/((1+sR₁C₁)(1+sR₂C₂)).'),
('11111111-1111-1111-1111-111111111111', 64, 'What are the corner frequencies in Bode plot analysis?', 'Frequencies where the slope of the magnitude plot changes. These occur at poles and zeros of the transfer function where ω equals the reciprocal of the time constant.'),
('11111111-1111-1111-1111-111111111111', 65, 'Define Gain Margin in frequency response analysis.', 'The amount of gain increase (in dB) required to make the system unstable. Found at the phase crossover frequency where phase = -180°.'),
('11111111-1111-1111-1111-111111111111', 66, 'Define Phase Margin in frequency response analysis.', 'The phase angle difference between the system response and -180° at the gain crossover frequency where |G(jω)| = 1 (0 dB).'),
('11111111-1111-1111-1111-111111111111', 67, 'What is the peak time (Tp) in a second-order underdamped system?', 'The time at which the response reaches its maximum overshoot, calculated as Tp = π/ωd where ωd is the damped natural frequency.'),
('11111111-1111-1111-1111-111111111111', 68, 'What is the settling time formula for a second-order underdamped system?', 'Ts = 4/(ζωn) for the 2% criterion, where ζ is the damping ratio and ωn is the natural frequency.'),
('11111111-1111-1111-1111-111111111111', 69, 'Express the maximum overshoot formula for a second-order underdamped system.', 'Mp = e^(-πζ/√(1-ζ²)) × 100%, where ζ is the damping ratio.'),
('11111111-1111-1111-1111-111111111111', 70, 'Solve the differential equation y'''' + 5y'' + 6y = 2e^(-t) with y(0) = 1, y''(0) = 0 using Laplace Transforms.', 'First, take Laplace transforms of both sides: [s²Y(s) - s] + [5sY(s) - 5] + 6Y(s) = 2/(s+1). Rearranging: Y(s)(s² + 5s + 6) = 2/(s+1) + s + 5 = (s² + 6s + 7)/(s+1). Factor: s² + 5s + 6 = (s+2)(s+3). Using partial fractions: Y(s) = 1/(s+1) + 1/(s+2) - 1/(s+3). Inverse Laplace: y(t) = e^(-t) + e^(-2t) - e^(-3t).'),
('11111111-1111-1111-1111-111111111111', 71, 'What is partial fraction decomposition?', 'A method to break down a rational function into simpler fractions that can be easily inverse transformed. For distinct linear factors, use A/(s-a) + B/(s-b) + ... form.'),
('11111111-1111-1111-1111-111111111111', 72, 'How do you apply the cover-up method in partial fractions?', 'To find coefficient A for factor (s-a) in denominator, multiply the entire expression by (s-a) and evaluate at s=a.'),
('11111111-1111-1111-1111-111111111111', 73, 'Define the damping ratio (ζ) in control systems.', 'A dimensionless parameter that describes the effect of damping on a second-order system. ζ < 1 is underdamped, ζ = 1 is critically damped, ζ > 1 is overdamped.'),
('11111111-1111-1111-1111-111111111111', 74, 'What is the natural frequency (ωn) in a second-order system?', 'The frequency at which the system oscillates when there is no damping (ζ = 0). Also called the undamped natural frequency.'),
('11111111-1111-1111-1111-111111111111', 75, 'Define the damped frequency (ωd) in a second-order system.', 'The actual oscillation frequency of an underdamped second-order system, calculated as ωd = ωn√(1 - ζ²).'),
('11111111-1111-1111-1111-111111111111', 76, 'What is steady-state error in a control system?', 'The difference between the desired reference input and the actual output after transients have died away and steady state is reached.'),
('11111111-1111-1111-1111-111111111111', 77, 'Explain the type of a control system based on steady-state error.', 'The type number indicates how many integrators (poles at origin) are in the open-loop transfer function. Type 0 has zero integrators, Type 1 has one integrator, etc.'),
('11111111-1111-1111-1111-111111111111', 78, 'What is the error constant for a Type 0 system?', 'The position error constant Kp = lim[s→0] G(s). It determines steady-state error to step inputs.'),
('11111111-1111-1111-1111-111111111111', 79, 'What is the error constant for a Type 1 system?', 'The velocity error constant Kv = lim[s→0] sG(s). It determines steady-state error to ramp inputs.'),
('11111111-1111-1111-1111-111111111111', 80, 'What is the error constant for a Type 2 system?', 'The acceleration error constant Ka = lim[s→0] s²G(s). It determines steady-state error to parabolic inputs.'),
('11111111-1111-1111-1111-111111111111', 81, 'Define a Lead compensator.', 'A compensation network that adds a zero ahead of (to the left of) its pole in the s-plane. Used to improve transient response and increase phase margin.'),
('11111111-1111-1111-1111-111111111111', 82, 'Define a Lag compensator.', 'A compensation network that adds a pole ahead of (to the right of) its zero in the s-plane. Used to improve steady-state error without significantly affecting transient response.'),
('11111111-1111-1111-1111-111111111111', 83, 'What is root locus analysis?', 'A graphical method to analyze how poles of a closed-loop system move as a parameter (usually gain K) varies from 0 to infinity.'),
('11111111-1111-1111-1111-111111111111', 84, 'State the Routh-Hurwitz Stability Criterion.', 'A method to determine system stability without finding poles. Arrange coefficients of characteristic equation in rows and check sign changes in first column. No sign changes means stability.'),
('11111111-1111-1111-1111-111111111111', 85, 'What is a bode plot?', 'A graphical representation of a system''s frequency response. It consists of two plots: magnitude (in dB) vs. log frequency and phase (in degrees) vs. log frequency.'),
('11111111-1111-1111-1111-111111111111', 86, 'Define the crossover frequency in Bode analysis.', 'Frequency where a specific property occurs. Gain crossover is where magnitude = 1 (0 dB). Phase crossover is where phase = -180°.'),
('11111111-1111-1111-1111-111111111111', 87, 'What is bandwidth in a control system?', 'The range of frequencies over which the system responds adequately. Usually defined as the frequency where magnitude drops to -3 dB (0.707 times peak).'),
('11111111-1111-1111-1111-111111111111', 88, 'Explain resonance in a control system.', 'Occurs when input frequency equals the system''s natural frequency, causing amplified output. Resonant peak is maximum magnitude response.'),
('11111111-1111-1111-1111-111111111111', 89, 'What is the definition of relative stability?', 'A measure of how stable a system is relative to the stability boundary. Expressed in terms of gain margin and phase margin.'),
('11111111-1111-1111-1111-111111111111', 90, 'Define absolute stability.', 'Whether a system is stable or unstable. A system is absolutely stable if all poles are in the left half of the s-plane.'),
('11111111-1111-1111-1111-111111111111', 91, 'What is the purpose of a compensator in control systems?', 'To modify system performance by adjusting transient response, steady-state error, and stability margins. Can be lead, lag, or lead-lag.'),
('11111111-1111-1111-1111-111111111111', 92, 'Explain a First-order system.', 'A system described by a first-order differential equation. Has one pole and exhibits exponential response without oscillation. Time constant τ determines response speed.'),
('11111111-1111-1111-1111-111111111111', 93, 'Explain a Second-order system.', 'A system described by a second-order differential equation. Has two poles and can exhibit oscillatory or non-oscillatory response depending on damping ratio.'),
('11111111-1111-1111-1111-111111111111', 94, 'What is the characteristic equation of a system?', 'The denominator polynomial of the transfer function set to zero. Its roots (poles) determine system stability and transient response.'),
('11111111-1111-1111-1111-111111111111', 95, 'Define the step response of a system.', 'The output of a system when a unit step input is applied. Used to evaluate transient and steady-state performance.'),
('11111111-1111-1111-1111-111111111111', 96, 'What is the impulse response of a system?', 'The output of a system when a unit impulse input is applied. Related to the inverse Laplace transform of the transfer function.'),
('11111111-1111-1111-1111-111111111111', 97, 'Explain the Routh array construction.', 'Write characteristic equation in descending powers. Form array with coefficients in specific pattern. Check for sign changes in first column to determine number of unstable poles.'),
('11111111-1111-1111-1111-111111111111', 98, 'What is the sensitivity function in control systems?', 'S(s) = 1/(1 + L(s)) where L(s) = G(s)C(s)H(s). Measures how closed-loop transfer function changes with respect to open-loop variations.'),
('11111111-1111-1111-1111-111111111111', 99, 'Define a PID controller.', 'Proportional-Integral-Derivative controller. Output = Kp*e(t) + Ki*∫e(t)dt + Kd*de(t)/dt where e is error and Kp, Ki, Kd are tuning constants.'),
('11111111-1111-1111-1111-111111111111', 100, 'What is the purpose of the Proportional term in a PID controller?', 'Provides immediate response proportional to current error. Improves response speed but cannot eliminate steady-state error alone.'),
('11111111-1111-1111-1111-111111111111', 101, 'What is the purpose of the Integral term in a PID controller?', 'Eliminates steady-state error by integrating error over time. Accumulates error to drive system to setpoint but can cause overshoot.'),
('11111111-1111-1111-1111-111111111111', 102, 'What is the purpose of the Derivative term in a PID controller?', 'Improves transient response by damping oscillations. Responds to rate of change of error, adding damping without affecting steady-state.'),
('11111111-1111-1111-1111-111111111111', 103, 'What is Ziegler-Nichols tuning method?', 'An empirical method for tuning PID controllers. Uses quarter-amplitude decay criterion or ultimate gain/period method to determine Kp, Ki, Kd.'),
('11111111-1111-1111-1111-111111111111', 104, 'Define pole placement control design.', 'A state-feedback control method where desired closed-loop poles are specified, and feedback gains are computed to achieve those pole locations.'),
('11111111-1111-1111-1111-111111111111', 105, 'What is Full State Feedback?', 'Using all state variables as feedback with gains to place poles at desired locations. Provides complete state information for control decisions.'),
('11111111-1111-1111-1111-111111111111', 106, 'Define Controllability.', 'A system is controllable if any initial state can be driven to zero in finite time by applying appropriate control input.'),
('11111111-1111-1111-1111-111111111111', 107, 'Define Observability.', 'A system is observable if the initial state can be determined from knowledge of the output over finite time.'),
('11111111-1111-1111-1111-111111111111', 108, 'What is a state observer?', 'A dynamic system that estimates unmeasured state variables from measured outputs. Allows state feedback when full state measurement is unavailable.'),
('11111111-1111-1111-1111-111111111111', 109, 'Explain the separation principle.', 'A control design principle allowing separate design of state feedback and observer. Pole placement and observer design can be done independently.'),
('11111111-1111-1111-1111-111111111111', 110, 'What is the industrial protocol Modbus?', 'A serial communication protocol for PLCs and industrial devices. Uses master-slave architecture with coils, discrete inputs, holding registers, and input registers.'),
('11111111-1111-1111-1111-111111111111', 111, 'Define the Profibus protocol.', 'A fieldbus communication standard for industrial automation. Supports high-speed digital communication between sensors, actuators, and control systems.'),
('11111111-1111-1111-1111-111111111111', 112, 'What is the Ethernet/IP protocol?', 'An industrial communication protocol based on standard Ethernet. Allows real-time communication for control and information applications in industrial networks.'),
('11111111-1111-1111-1111-111111111111', 113, 'Explain the CAN bus protocol.', 'Controller Area Network. A serial communication bus used extensively in automotive and industrial applications for real-time message passing.'),
('11111111-1111-1111-1111-111111111111', 114, 'What is the purpose of industrial communication protocols?', 'Enable devices on plant floor to exchange data reliably in real-time. Standardize communication between equipment from different manufacturers.'),
('11111111-1111-1111-1111-111111111111', 115, 'Define a Sensor conditioning circuit.', 'Electronic circuitry that processes raw sensor signals (amplification, filtering, linearization) to produce output suitable for measurement or control.'),
('11111111-1111-1111-1111-111111111111', 116, 'What is signal filtering?', 'A process to remove unwanted noise and high-frequency components from signals. Common filters are low-pass, high-pass, band-pass, and band-stop.'),
('11111111-1111-1111-1111-111111111111', 117, 'Explain a Low-pass filter.', 'Allows low frequencies to pass while attenuating high frequencies. Used to remove noise from sensor signals. Cutoff frequency determines the boundary.'),
('11111111-1111-1111-1111-111111111111', 118, 'What is a High-pass filter?', 'Allows high frequencies to pass while attenuating low frequencies. Used to remove DC offset and low-frequency noise from signals.'),
('11111111-1111-1111-1111-111111111111', 119, 'Define a Band-pass filter.', 'Allows frequencies within a specific band to pass while attenuating frequencies outside. Used to select signals within specific frequency range.'),
('11111111-1111-1111-1111-111111111111', 120, 'What is a Band-stop (notch) filter?', 'Attenuates frequencies within specific band while allowing frequencies outside. Used to remove interference at specific frequency like 50 Hz line noise.'),
('11111111-1111-1111-1111-111111111111', 121, 'Explain the purpose of an Anti-aliasing filter.', 'A low-pass filter applied before analog-to-digital conversion. Removes frequencies higher than Nyquist frequency to prevent aliasing errors.'),
('11111111-1111-1111-1111-111111111111', 122, 'What is the Nyquist frequency?', 'Half the sampling frequency. Highest frequency that can be accurately represented in sampled data without aliasing.'),
('11111111-1111-1111-1111-111111111111', 123, 'Define Digital-to-Analog Converter (DAC).', 'Electronic device that converts digital signals (binary numbers) into continuous analog voltage or current outputs.'),
('11111111-1111-1111-1111-111111111111', 124, 'Define Analog-to-Digital Converter (ADC).', 'Electronic device that converts continuous analog voltage or current inputs into digital signals (binary numbers).'),
('11111111-1111-1111-1111-111111111111', 125, 'What is the resolution of an ADC?', 'The smallest change in analog input that produces a change in digital output. Determined by number of bits: n-bit ADC has 2^n different levels.'),
('11111111-1111-1111-1111-111111111111', 126, 'Explain quantization error in ADC.', 'The error introduced when continuous analog signal is converted to discrete digital values. Maximum error is half of one least significant bit.'),
('11111111-1111-1111-1111-111111111111', 127, 'What is sampling rate in digital control?', 'The frequency at which analog signals are converted to digital. Must be at least twice the highest frequency component (Nyquist criterion).'),
('11111111-1111-1111-1111-111111111111', 128, 'Define the Z-transform.', 'Mathematical tool for analyzing discrete-time systems. Transforms discrete-time sequences into complex plane Z-domain, similar to Laplace for continuous systems.'),
('11111111-1111-1111-1111-111111111111', 129, 'What is the relationship between s-plane and z-plane?', 'z = e^(sT) where T is sampling period. Maps s-plane pole locations to z-plane. Left half s-plane maps inside unit circle in z-plane.'),
('11111111-1111-1111-1111-111111111111', 130, 'Explain stability in discrete-time systems.', 'A discrete system is stable if all poles are inside the unit circle |z| < 1 in the z-plane. Poles on unit circle indicate marginal stability.'),
('11111111-1111-1111-1111-111111111111', 131, 'What is a Hold circuit?', 'Digital-to-analog reconstruction device that holds analog output constant between sampling periods. Zero-order hold is most common.'),
('11111111-1111-1111-1111-111111111111', 132, 'Define the system matrix in state-space representation.', 'In state equation x'' = Ax + Bu, matrix A is nxn system matrix describing how state variables interact.'),
('11111111-1111-1111-1111-111111111111', 133, 'Define the input matrix in state-space representation.', 'In state equation x'' = Ax + Bu, matrix B is nxm input matrix describing how inputs affect states.'),
('11111111-1111-1111-1111-111111111111', 134, 'Define the output matrix in state-space representation.', 'In output equation y = Cx + Du, matrix C is pxn output matrix describing how states contribute to output.'),
('11111111-1111-1111-1111-111111111111', 135, 'Define the feedthrough matrix in state-space representation.', 'In output equation y = Cx + Du, matrix D is pxm feedthrough matrix describing direct input-output coupling.'),
('11111111-1111-1111-1111-111111111111', 136, 'What is the advantage of state-space representation?', 'Can represent multiple inputs and outputs. Easier to implement digitally. Provides complete system description including internal dynamics.'),
('11111111-1111-1111-1111-111111111111', 137, 'Explain conversion from transfer function to state-space.', 'Canonical forms include controllable canonical form (companion matrix) and observable canonical form. Different forms reveal different system properties.'),
('11111111-1111-1111-1111-111111111111', 138, 'What is the Lyapunov stability criterion?', 'A method to determine stability without finding eigenvalues. If symmetric positive-definite matrix P exists satisfying A^T P + PA = -Q (Q positive-definite), system is stable.'),
('11111111-1111-1111-1111-111111111111', 139, 'Define a Hydraulic actuator.', 'A device converting hydraulic pressure into mechanical motion. Can produce high forces and precise control. Types include cylinders and hydraulic motors.'),
('11111111-1111-1111-1111-111111111111', 140, 'Explain a Pneumatic actuator.', 'A device converting compressed air pressure into mechanical motion. Safer than hydraulic, used for simple on-off or proportional control applications.'),
('11111111-1111-1111-1111-111111111111', 141, 'What is an Electric actuator?', 'A device converting electrical energy into mechanical motion. Types include DC motors, AC motors, stepper motors, servo motors with various control methods.'),
('11111111-1111-1111-1111-111111111111', 142, 'Define a Stepper motor.', 'An electric motor that rotates in discrete steps. Steps directly proportional to input pulses. Used in positioning applications without feedback.'),
('11111111-1111-1111-1111-111111111111', 143, 'What is a Servo motor?', 'An electric motor with integrated feedback control. Maintains precise speed and position. Used in precision applications like robotics and CNC machines.'),
('11111111-1111-1111-1111-111111111111', 144, 'Explain a DC motor.', 'An electric motor using commutator and brushes. Speed proportional to applied voltage, torque proportional to current. Simple to control with PWM.'),
('11111111-1111-1111-1111-111111111111', 145, 'What is an AC induction motor?', 'An electric motor where rotating magnetic field induces currents in rotor. Widely used in industrial applications. Speed roughly proportional to frequency.'),
('11111111-1111-1111-1111-111111111111', 146, 'Define brake torque in an actuator.', 'Maximum torque or force that an actuator can hold or produce. Important for load-holding and emergency stop applications.'),
('11111111-1111-1111-1111-111111111111', 147, 'What is response time of an actuator?', 'Time required for actuator to respond to control signal. Affects system response speed. Must be considered in control system design.'),
('11111111-1111-1111-1111-111111111111', 148, 'Explain the concept of hysteresis in actuators.', 'Difference between forward and reverse response curves. Causes dead zone where small input changes produce no output. Must be compensated in control systems.'),
('11111111-1111-1111-1111-111111111111', 149, 'What is a Pressure relief valve?', 'Safety device that opens when pressure exceeds set level, allowing fluid to return to tank. Prevents overpressure damage to system.'),
('11111111-1111-1111-1111-111111111111', 150, 'Define a Flow control valve.', 'Device regulating volumetric flow rate of fluid. Used to control speed of actuators. Types include needle valves, proportional valves, and directional control valves.'),
('11111111-1111-1111-1111-111111111111', 151, 'What is a Proportional directional control valve?', 'A valve where spool position is proportional to electrical input signal. Provides variable flow and direction control. Used in servo systems.'),
('11111111-1111-1111-1111-111111111111', 152, 'Explain a Solenoid valve.', 'An electrical on-off valve. Solenoid coil creates magnetic force moving poppet. Used for rapid on-off control in pneumatic and hydraulic systems.'),
('11111111-1111-1111-1111-111111111111', 153, 'What is a Check valve?', 'A one-way valve allowing flow in one direction only. Prevents backflow. Used for safety and load holding in hydraulic systems.'),
('11111111-1111-1111-1111-111111111111', 154, 'Define Fluid power in industrial automation.', 'Use of pressurized fluids (liquid or gas) to produce mechanical motion and control. Includes hydraulic and pneumatic systems.'),
('11111111-1111-1111-1111-111111111111', 155, 'Explain the advantages of Hydraulic systems.', 'High power-to-weight ratio, smooth operation, precise control, load-holding capability. Used for heavy machinery and precision applications.'),
('11111111-1111-1111-1111-111111111111', 156, 'What are the disadvantages of Hydraulic systems?', 'Complex, maintenance-intensive, potential leakage hazards, environmental concerns, high cost, slower response than electrical.'),
('11111111-1111-1111-1111-111111111111', 157, 'Explain the advantages of Pneumatic systems.', 'Safe, clean, simple, fast response, low maintenance. Good for on-off applications. Suitable for hazardous environments.'),
('11111111-1111-1111-1111-111111111111', 158, 'What are the disadvantages of Pneumatic systems?', 'Lower force/torque than hydraulic for same size, compressibility causes poor precision, energy inefficiency due to compressor losses.'),
('11111111-1111-1111-1111-111111111111', 159, 'Define the compressor in a pneumatic system.', 'Device that draws in atmospheric air and increases pressure. Can be reciprocating (piston), rotary screw, or centrifugal type.'),
('11111111-1111-1111-1111-111111111111', 160, 'What is an Air receiver (tank) in pneumatic systems?', 'Storage vessel that accumulates compressed air. Smooths pressure fluctuations and provides buffer for peak demand.'),
('11111111-1111-1111-1111-111111111111', 161, 'Explain the function of a Regulator in pneumatic systems.', 'Device that reduces supply pressure to working pressure and maintains constant output pressure despite fluctuations in supply or load.'),
('11111111-1111-1111-1111-111111111111', 162, 'What is a Lubricator in a pneumatic system?', 'Device that injects fine mist of oil into compressed air. Lubricates moving parts of pneumatic equipment to reduce wear.'),
('11111111-1111-1111-1111-111111111111', 163, 'Define a Muffler in pneumatic systems.', 'Device that silences exhaust air from pneumatic equipment. Reduces noise pollution from venting compressed air to atmosphere.'),
('11111111-1111-1111-1111-111111111111', 164, 'What is a Dryer in a pneumatic system?', 'Device that removes moisture from compressed air. Prevents corrosion and freezing of components. Types include refrigerant and desiccant dryers.'),
('11111111-1111-1111-1111-111111111111', 165, 'Explain the function of a Pressure gauge in pneumatic systems.', 'Measures and indicates system pressure. Essential for monitoring operation and detecting faults. Types include analog (Bourdon tube) and digital.'),
('11111111-1111-1111-1111-111111111111', 166, 'What is pneumatic cylinder design?', 'Can be single-acting (spring return) or double-acting (powered return). Bore size determines force output. Stroke length determines travel distance.'),
('11111111-1111-1111-1111-111111111111', 167, 'Define the rod area in a pneumatic cylinder.', 'Cross-sectional area of the cylinder rod. Used in calculations for double-acting cylinders as piston area equals bore area minus rod area on return stroke.'),
('11111111-1111-1111-1111-111111111111', 168, 'What is a Limit switch in pneumatic systems?', 'An electromechanical switch operated by position of cylinder rod. Used to stop actuation at desired position or trigger control actions.'),
('11111111-1111-1111-1111-111111111111', 169, 'Explain throttle valve operation.', 'A flow control valve that restricts flow to adjust speed. Creates pressure drop across valve. Used to control speed of actuators in one direction.'),
('11111111-1111-1111-1111-111111111111', 170, 'What is Back pressure in actuator control?', 'Resistance pressure in return line of double-acting actuator. Affects force output and speed control. Must be considered in circuit design.'),
('11111111-1111-1111-1111-111111111111', 171, 'Define a Counterbalance valve.', 'A valve that maintains minimum back pressure on actuator. Prevents free fall under load and provides smooth lowering control in vertical applications.'),
('11111111-1111-1111-1111-111111111111', 172, 'What is a Load-holding valve?', 'A valve that prevents load from drifting when control signal is removed. Uses pilot pressure to override check valve. Essential for safety in vertical applications.'),
('11111111-1111-1111-1111-111111111111', 173, 'Explain pilot pressure in pneumatic/hydraulic valves.', 'Low-pressure signal used to operate larger valves. Allows small signal to control large flow. Used in proportional and servo valves.'),
('11111111-1111-1111-1111-111111111111', 174, 'What is system pressure in a hydraulic system?', 'Working pressure maintained by pump and regulator. Determines component ratings and system force/torque capability. Typical range 210-350 bar.'),
('11111111-1111-1111-1111-111111111111', 175, 'Define volumetric efficiency of a hydraulic pump.', 'Ratio of actual output flow to theoretical flow based on displacement and speed. Accounts for internal leakage. Typically 90-95%.'),
('11111111-1111-1111-1111-111111111111', 176, 'What is mechanical efficiency of a hydraulic pump?', 'Ratio of theoretical power output to actual input power. Accounts for friction losses. Product of volumetric and mechanical efficiency is overall efficiency.'),
('11111111-1111-1111-1111-111111111111', 177, 'Explain cavitation in hydraulic systems.', 'Formation of vapor bubbles when local pressure drops below fluid vapor pressure. Causes noise, erosion, and damage. Prevented by maintaining adequate inlet pressure.'),
('11111111-1111-1111-1111-111111111111', 178, 'What is an Accumulator in hydraulic systems?', 'Energy storage device using gas-charged bladder or piston. Stores pressurized fluid for peak demand or emergency operation. Improves system response.'),
('11111111-1111-1111-1111-111111111111', 179, 'Define Viscosity in hydraulic fluids.', 'Measure of fluid''s resistance to flow. High viscosity reduces efficiency but improves seal performance. Viscosity index indicates temperature sensitivity.'),
('11111111-1111-1111-1111-111111111111', 180, 'What is the purpose of a Heat exchanger in hydraulic systems?', 'Removes heat generated by friction and throttling. Maintains fluid temperature within operating range. Prevents fluid degradation and component damage.'),
('11111111-1111-1111-1111-111111111111', 181, 'Explain the purpose of a Filter in hydraulic systems.', 'Removes contaminant particles from fluid. Prevents damage to precision components. Micronic rating specifies particle size removal capability.'),
('11111111-1111-1111-1111-111111111111', 182, 'What is seal degradation in hydraulic systems?', 'Seals lose effectiveness due to heat, pressure, and fluid degradation. Causes internal leakage and eventual system failure. Regular maintenance prolongs seal life.'),
('11111111-1111-1111-1111-111111111111', 183, 'Define a Proportional valve in hydraulic systems.', 'Valve where spool position is proportional to electrical input. Provides variable flow and pressure control with moderate response time. Cost-effective servo control.'),
('11111111-1111-1111-1111-111111111111', 184, 'What is a Servo valve in hydraulic systems?', 'High-performance valve with fast response and high precision. Uses electronics for feedback control. Expensive but essential for precision applications.'),
('11111111-1111-1111-1111-111111111111', 185, 'Explain dither signal in proportional/servo valves.', 'High-frequency small amplitude signal superimposed on input. Overcomes valve hysteresis and stiction. Improves resolution and control smoothness.'),
('11111111-1111-1111-1111-111111111111', 186, 'What is a T-slot profile in industrial framing?', 'Aluminum extrusion with T-shaped slots for mounting components. Allows flexible modular assembly of frames and machine structures.'),
('11111111-1111-1111-1111-111111111111', 187, 'Define precision in linear motion systems.', 'Ability to position load at specific location. Determined by bearing play, screw backlash, and controller resolution. Critical for accurate positioning.'),
('11111111-1111-1111-1111-111111111111', 188, 'What is repeatability in motion systems?', 'Ability to return to same position multiple times. Important for consistent product quality in manufacturing. Usually better than absolute accuracy.'),
('11111111-1111-1111-1111-111111111111', 189, 'Explain backlash in ball screw drives.', 'Clearance between screw and nut causing position lag. Preloading reduces but increases friction and wear. Must be controlled for precision positioning.'),
('11111111-1111-1111-1111-111111111111', 190, 'What is a Linear bearing system?', 'Uses ball or roller bearings to enable smooth linear motion with low friction. Types include ball bushings on shafts and linear guides.'),
('11111111-1111-1111-1111-111111111111', 191, 'Define a Lead screw.', 'Mechanical device converting rotary motion to linear motion. Pitch determines linear distance per revolution. Used in precision positioning and vertical lifting.'),
('11111111-1111-1111-1111-111111111111', 192, 'What is a Ball screw?', 'Lead screw using ball bearings for low friction and smooth motion. High efficiency and precision. More expensive than acme screws but superior performance.'),
('11111111-1111-1111-1111-111111111111', 193, 'Explain preload in a ball screw assembly.', 'Force applied to eliminate backlash and play. Improves accuracy and stiffness. Must balance between eliminating backlash and not causing excessive friction.'),
('11111111-1111-1111-1111-111111111111', 194, 'What is a Pulley and belt drive system?', 'Uses timing belt or V-belt to transfer motion. Simple and quiet but subject to slip. Timing belts provide no-slip capability for precise positioning.'),
('11111111-1111-1111-1111-111111111111', 195, 'Define gear ratio in mechanical systems.', 'Ratio of input teeth to output teeth. Determines speed multiplication or reduction. Higher ratio means more speed reduction and torque multiplication.'),
('11111111-1111-1111-1111-111111111111', 196, 'What is torque ripple in gear systems?', 'Variation in output torque as gears mesh. Causes vibration and noise. Precision-made gears with proper backlash minimize ripple.'),
('11111111-1111-1111-1111-111111111111', 197, 'Explain strain gauge for force/pressure measurement.', 'Electrical resistor that changes resistance when strained. Bonded to structure under test. Four-gauge Wheatstone bridge eliminates temperature effects and improves linearity.'),
('11111111-1111-1111-1111-111111111111', 198, 'What is load cell application?', 'Device using strain gauges to measure weight or force. Common in scales, load platforms, and force sensors for testing. Output is electrical signal proportional to force.'),
('11111111-1111-1111-1111-111111111111', 199, 'Define signal-to-noise ratio (SNR) in measurement systems.', 'Ratio of desired signal power to noise power. Higher ratio indicates better measurement quality. Expressed in decibels (dB).'),
('11111111-1111-1111-1111-111111111111', 200, 'What is temperature compensation in sensors?', 'Method to eliminate errors caused by temperature changes. Can be hardware (reference voltage) or software (calibration curves). Essential for accuracy across temperature range.'),
('11111111-1111-1111-1111-111111111111', 201, 'Explain the linearity of a sensor.', 'Degree to which sensor output varies proportionally with input. Ideal sensor has perfect linearity. Non-linearity must be compensated in signal conditioning or software.'),
('11111111-1111-1111-1111-111111111111', 202, 'What is hysteresis error in sensors?', 'Difference between readings taken while increasing vs. decreasing input. Causes path-dependent output. Must be minimized through proper sensor design and measurement technique.'),
('22222222-2222-2222-2222-222222222222', 16, 'Define calibration of instruments.', 'Process of comparing instrument output to known standards. Determines accuracy and establishes correction factors. Must be performed periodically for measurement traceability.'),
('22222222-2222-2222-2222-222222222222', 17, 'What is the purpose of a Wheatstone bridge?', 'Electrical circuit that measures small resistance changes precisely. Uses four resistive elements balanced condition. One arm changes with physical parameter being measured.'),
('22222222-2222-2222-2222-222222222222', 18, 'Explain the RTD (Resistance Temperature Detector) sensor.', 'Uses resistance change of pure metal (usually platinum) to measure temperature. Linear over wide range. Requires current source and measurement of resistance.'),
('22222222-2222-2222-2222-222222222222', 19, 'What is a Thermocouple?', 'Two dissimilar metals joined together creating electromotive force when heated. Output voltage proportional to temperature difference. Requires cold junction reference compensation.'),
('22222222-2222-2222-2222-222222222222', 20, 'Define thermistor.', 'Semiconductor resistor with strong temperature dependence. Smaller size than RTD with faster response. Non-linear response requires calibration curves.'),
('22222222-2222-2222-2222-222222222222', 21, 'What is a Pyrometer?', 'Non-contact temperature measurement device using infrared radiation. Measures surface temperature by analyzing thermal radiation. Essential for inaccessible or moving objects.'),
('22222222-2222-2222-2222-222222222222', 22, 'Explain capacitive sensor principle.', 'Measures change in capacitance between plates. Capacitance changes with dielectric constant or distance between plates. Used for position, level, and humidity measurement.'),
('22222222-2222-2222-2222-222222222222', 23, 'What is an Inductive sensor?', 'Uses change in inductance to detect metal objects. Operates without contact. Common in proximity detection and position sensing applications.'),
('22222222-2222-2222-2222-222222222222', 24, 'Define LVDT (Linear Variable Differential Transformer).', 'Electromechanical transducer measuring linear displacement. Primary coil energized, secondary coils detect position of movable core. Excellent linearity and durability.'),
('22222222-2222-2222-2222-222222222222', 25, 'What is a Magnetic sensor?', 'Detects magnetic field strength and direction. Types include Hall effect sensors and magnetoresistive sensors. Used for position sensing and proximity detection.'),
('22222222-2222-2222-2222-222222222222', 26, 'Explain the Hall effect in sensors.', 'Voltage develops perpendicular to current when conductor placed in magnetic field. Magnitude proportional to magnetic field strength. Used in position and current sensing.'),
('22222222-2222-2222-2222-222222222222', 27, 'What is a Tachometer generator?', 'Device converting rotational speed to electrical signal. DC tachometer output is DC voltage proportional to speed. Used for speed feedback in servo systems.'),
('22222222-2222-2222-2222-222222222222', 28, 'Define pressure sensor types.', 'Absolute pressure sensors measure actual pressure. Gauge pressure sensors measure pressure above atmospheric. Differential pressure sensors measure pressure difference between two points.'),
('22222222-2222-2222-2222-222222222222', 29, 'What is a Bellows element in pressure measurement?', 'Flexible metal tube that expands with pressure. Simple and rugged. Used in analog pressure gauges and as transducer for pressure switches.'),
('22222222-2222-2222-2222-222222222222', 30, 'Explain bourdon tube operation.', 'Curved metallic tube that straightens when pressure applied. Movement is proportional to pressure. Connected to needle indicating pressure on dial face.'),
('22222222-2222-2222-2222-222222222222', 31, 'What is a Diaphragm pressure sensor?', 'Flexible membrane deflects proportionally to pressure difference. Deflection measured by strain gauges or capacitive method. Used in modern electronic pressure transmitters.'),
('22222222-2222-2222-2222-222222222222', 32, 'Define liquid level measurement methods.', 'Float method uses buoyancy. Capacitive method measures dielectric change. Ultrasonic method measures time-of-flight. Each has advantages and limitations.'),
('22222222-2222-2222-2222-222222222222', 33, 'What is a Flow meter classification?', 'Turbine meters measure volumetric flow from rotation rate. Vortex meters detect vortex shedding frequency. Electromagnetic meters suitable for conductive fluids. Ultrasonic meters non-intrusive measurement.'),
('22222222-2222-2222-2222-222222222222', 34, 'Explain Coriolis mass flow meter principle.', 'Vibrating tubes deflect due to Coriolis force from flowing fluid. Deflection proportional to mass flow rate. Measures true mass flow unaffected by density changes.'),
('22222222-2222-2222-2222-222222222222', 35, 'What is a Spectral analysis in signal processing?', 'Frequency domain analysis showing signal content at different frequencies. Fast Fourier Transform (FFT) computes frequency components. Used for vibration analysis and fault detection.'),
('22222222-2222-2222-2222-222222222222', 36, 'Define Power spectral density (PSD).', 'Represents power distribution across frequency spectrum. Useful for identifying dominant frequency components and system resonances. Used in vibration and noise analysis.'),
('22222222-2222-2222-2222-222222222222', 37, 'What is a Window function in FFT analysis?', 'Applied to signal before FFT to reduce spectral leakage. Different windows (Hanning, Hamming, Blackman) offer trade-offs between frequency resolution and amplitude accuracy.'),
('22222222-2222-2222-2222-222222222222', 38, 'Explain aliasing in digital signal processing.', 'Occurs when sampling frequency too low, causing high frequencies to appear as lower frequencies. Prevented by sampling at least twice highest signal frequency (Nyquist criterion).'),
('22222222-2222-2222-2222-222222222222', 39, 'What is downsampling in digital signal processing?', 'Reducing sampling rate by discarding samples. Must be preceded by low-pass filtering to prevent aliasing. Used to reduce data rate and computational load.'),
('22222222-2222-2222-2222-222222222222', 40, 'Define finite impulse response (FIR) filter.', 'Digital filter where output depends only on current and past inputs. Has finite length impulse response. Always stable, can have linear phase.'),
('22222222-2222-2222-2222-222222222222', 41, 'What is infinite impulse response (IIR) filter?', 'Digital filter where output depends on current/past inputs and past outputs. Has infinite length impulse response. More efficient than FIR but requires stability verification.'),
('22222222-2222-2222-2222-222222222222', 42, 'Explain z-transform of a sampled signal.', 'X(z) = sum of x[n]*z^(-n). Maps discrete sequences to complex plane Z-domain. Poles and zeros determine system characteristics and stability.'),
('22222222-2222-2222-2222-222222222222', 43, 'What is a State estimator or Observer?', 'Reconstructs full state vector from limited measurements. Luenberger observer uses estimated output error to correct state estimate. Essential when full state not measurable.'),
('22222222-2222-2222-2222-222222222222', 44, 'Define observability matrix.', 'Matrix [C; CA; CA²; ...; CA^(n-1)] determining if system is observable. Full rank indicates all states can be estimated from output measurements.'),
('22222222-2222-2222-2222-222222222222', 45, 'What is controllability matrix?', 'Matrix [B AB A²B ... A^(n-1)B] determining if system is controllable. Full rank indicates all poles can be placed arbitrarily through state feedback.'),
('22222222-2222-2222-2222-222222222222', 46, 'Explain modal analysis in control systems.', 'Decomposes system into natural modes (eigenmodes). Each mode has eigenvalue (pole) and eigenvector (mode shape). Understanding modes guides controller design.'),
('22222222-2222-2222-2222-222222222222', 47, 'What is deadbeat control?', 'Discrete-time controller design where system reaches desired state in finite steps without oscillation. Provides fastest possible response but may require large control effort.'),
('22222222-2222-2222-2222-222222222222', 48, 'Define optimal control problem.', 'Design control to minimize cost function (e.g., energy, time, error). Linear Quadratic Regulator (LQR) minimizes weighted sum of state and input energy.'),
('22222222-2222-2222-2222-222222222222', 49, 'What is Model Predictive Control (MPC)?', 'Control algorithm using predicted system behavior to optimize future inputs. Uses system model to predict outcomes. Handles constraints naturally.'),
('22222222-2222-2222-2222-222222222222', 50, 'Explain fuzzy logic control.', 'Uses fuzzy sets and linguistic rules instead of precise logic. Provides control for systems difficult to model analytically. Combines expert knowledge with automated control.'),
('22222222-2222-2222-2222-222222222222', 51, 'What is neural network control?', 'Uses artificial neural networks to approximate control strategy. Learns from data. Useful for non-linear systems and systems without good models.'),
('22222222-2222-2222-2222-222222222222', 52, 'Define expert systems in industrial automation.', 'Software systems capturing expert knowledge in rule form. Provides decision support and diagnostics. Can diagnose faults and suggest corrective actions.'),
('22222222-2222-2222-2222-222222222222', 53, 'What is a Programmable Logic Controller (PLC) hardware?', 'Consists of CPU module, input/output modules, power supply, programming interface. Modular design allows customization for specific applications.'),
('22222222-2222-2222-2222-222222222222', 54, 'Explain ladder logic programming.', 'Programming language resembling electrical relay circuits. Rungs represent logic operations. Most intuitive for control engineers familiar with electrical schematics.'),
('22222222-2222-2222-2222-222222222222', 55, 'What is structured text programming?', 'Text-based programming language resembling Pascal. Allows complex programming constructs. More powerful than ladder logic for complex algorithms.'),
('22222222-2222-2222-2222-222222222222', 56, 'Define function block diagram (FBD) programming.', 'Graphical programming using function blocks connected by wires. Each block performs specific function. Good for complex control logic and data flow visualization.'),
('22222222-2222-2222-2222-222222222222', 57, 'What is scan cycle in PLC operation?', 'Continuous sequence of reading inputs, executing program, writing outputs. Typical cycle time 10-50 ms. Deterministic timing important for real-time control.'),
('22222222-2222-2222-2222-222222222222', 58, 'Explain interrupt programming in PLC.', 'Asynchronous event handling when specific condition occurs. Interrupts normal program execution. Used for time-critical tasks and fast response requirements.'),
('22222222-2222-2222-2222-222222222222', 59, 'What is an Analog input module?', 'PLC module that reads analog signals and converts to digital. Resolution typically 12-16 bits. Provides analog measurements from sensors and instruments.'),
('22222222-2222-2222-2222-222222222222', 60, 'Define analog output module.', 'PLC module that converts digital values to analog signals. Resolution typically 12-16 bits. Drives analog actuators and displays from discrete outputs.'),
('22222222-2222-2222-2222-222222222222', 61, 'What is a Communication module in PLC systems?', 'Enables PLC communication with other devices via industrial protocols. Supports Modbus, Profibus, Ethernet, etc. Allows distributed control and monitoring.'),
('22222222-2222-2222-2222-222222222222', 62, 'Explain real-time operating system (RTOS) role in automation.', 'Manages task scheduling with deterministic timing. Ensures critical tasks run on schedule. Essential for time-critical control applications.'),
('22222222-2222-2222-2222-222222222222', 63, 'What is task scheduling in RTOS?', 'Algorithm determining order and timing of task execution. Priority-based scheduling runs high-priority tasks first. Rate-monotonic scheduling good for periodic tasks.'),
('22222222-2222-2222-2222-222222222222', 64, 'Define interrupt latency.', 'Delay between interrupt request and interrupt handler execution. Must be minimal for real-time control. Predictable latency more important than absolute minimum.'),
('22222222-2222-2222-2222-222222222222', 65, 'What is semaphore in real-time programming?', 'Synchronization mechanism preventing multiple tasks accessing shared resources simultaneously. Binary semaphore for mutual exclusion. Counting semaphore for resource management.'),
('22222222-2222-2222-2222-222222222222', 66, 'Explain message queue in embedded systems.', 'Data structure for inter-task communication. Enables asynchronous communication between tasks. Tasks post messages and other tasks retrieve when ready.'),
('22222222-2222-2222-2222-222222222222', 67, 'What is CRC (Cyclic Redundancy Check)?', 'Error detection method using polynomial division. Detects errors in transmitted data. Common in industrial protocols for data integrity verification.'),
('22222222-2222-2222-2222-222222222222', 68, 'Define parity bit error detection.', 'Extra bit added to data for error detection. Odd parity ensures odd number of ones. Even parity ensures even number of ones. Simple but limited error detection.'),
('22222222-2222-2222-2222-222222222222', 69, 'What is Hamming code?', 'Error correction code using parity bits in specific positions. Can correct single-bit errors and detect double-bit errors. Used in communication and memory applications.'),
('22222222-2222-2222-2222-222222222222', 70, 'Explain network protocol stack layers.', 'Physical layer transmits bits, Data link handles frames, Network layer routes packets, Transport ensures reliable delivery, Application provides services.'),
('22222222-2222-2222-2222-222222222222', 71, 'What is a SCADA system architecture?', 'Distributed system with RTUs or PLCs at field sites communicating with central control station. Allows monitoring and control of geographically dispersed processes.'),
('22222222-2222-2222-2222-222222222222', 72, 'Define Remote Terminal Unit (RTU).', 'Field device in SCADA collecting data and performing control. Uses local microprocessor for autonomous operation. Communicates with master station periodically or on demand.'),
('22222222-2222-2222-2222-222222222222', 73, 'What is a Supervisory layer in SCADA?', 'Central station displaying system status and allowing operator intervention. Provides alarm handling and historical logging. Makes high-level process decisions.'),
('22222222-2222-2222-2222-222222222222', 74, 'Explain redundancy in critical control systems.', 'Duplicate critical components to improve reliability. Redundant sensors provide voting for fault detection. Redundant controllers provide automatic failover.'),
('22222222-2222-2222-2222-222222222222', 75, 'What is heartbeat signal in industrial systems?', 'Periodic message confirming system is operational. Loss of heartbeat triggers alarm and possible failover. Simple method for detecting communication failures.'),
('22222222-2222-2222-2222-222222222222', 76, 'Define watchdog timer.', 'Timer that must be periodically reset by software. If not reset within timeout period, system resets. Detects software hangs or deadlocks.'),
('22222222-2222-2222-2222-222222222222', 77, 'What is graceful degradation in control systems?', 'System continues operation with reduced capability when faults occur. Maintains safety and stability. Preferable to complete shutdown in critical applications.'),
('22222222-2222-2222-2222-222222222222', 78, 'Explain hot standby redundancy.', 'Redundant system continuously running and synchronized with primary. No delay in switchover. More expensive but essential for critical applications.'),
('22222222-2222-2222-2222-222222222222', 79, 'What is cold standby redundancy?', 'Redundant system available but not running. Faster than maintenance but slower than hot standby. Balances cost and performance for medium-critical applications.'),
('22222222-2222-2222-2222-222222222222', 80, 'Define warm standby redundancy.', 'Redundant system running but not fully synchronized. Compromise between hot and cold standby. Provides reasonable response time with lower cost than hot standby.'),
('22222222-2222-2222-2222-222222222222', 81, 'What is a Fault tree analysis?', 'Graphical method analyzing system failures. Top event is system failure, branches show causes. Identifies critical components and common cause failures.'),
('22222222-2222-2222-2222-222222222222', 82, 'Explain Failure Mode and Effects Analysis (FMEA).', 'Systematic analysis of potential failures and their effects. Identifies critical failure modes and mitigation strategies. Improves design and operating procedures.'),
('22222222-2222-2222-2222-222222222222', 83, 'What is Six Sigma in manufacturing?', 'Quality improvement methodology targeting 3.4 defects per million opportunities. Uses statistical methods and process optimization. Reduces variation and improves consistency.'),
('22222222-2222-2222-2222-222222222222', 84, 'Define Total Productive Maintenance (TPM).', 'Philosophy maximizing equipment effectiveness. Involves operator maintenance, predictive maintenance, and equipment redesign. Improves reliability and reduces downtime.'),
('22222222-2222-2222-2222-222222222222', 85, 'What is preventive maintenance?', 'Scheduled maintenance performed at fixed intervals. Prevents failures before they occur. More economical than reactive maintenance but less efficient than predictive.'),
('22222222-2222-2222-2222-222222222222', 86, 'Explain predictive maintenance.', 'Monitoring equipment condition and performing maintenance when needed. Uses vibration analysis, temperature monitoring, oil analysis. Optimizes maintenance costs and uptime.'),
('22222222-2222-2222-2222-222222222222', 87, 'What is Condition monitoring?', 'Continuous or periodic measurement of equipment condition. Vibration, temperature, acoustic emission, ultrasound monitored. Provides early warning of developing faults.'),
('22222222-2222-2222-2222-222222222222', 88, 'Define Remaining Useful Life (RUL) prediction.', 'Estimating time until equipment failure. Uses monitoring data and failure models. Allows optimized maintenance planning.'),
('22222222-2222-2222-2222-222222222222', 89, 'What is root cause analysis?', 'Systematic investigation to determine why failure occurred. Prevents recurrence. Methods include 5-why analysis and fishbone diagrams.'),
('22222222-2222-2222-2222-222222222222', 90, 'Explain the principle of 5S in manufacturing.', 'Five Japanese practices: Sort, Set in Order, Shine, Standardize, Sustain. Improves workplace organization, safety, and efficiency.'),
('22222222-2222-2222-2222-222222222222', 91, 'What is Just-in-Time (JIT) manufacturing?', 'Production philosophy minimizing inventory by producing just when needed. Reduces waste and improves cash flow. Requires reliable suppliers and processes.'),
('22222222-2222-2222-2222-222222222222', 92, 'Define Lean manufacturing.', 'Eliminating waste to create efficient production. Focuses on continuous improvement and flow. Reduces inventory, defects, and cycle time.'),
('22222222-2222-2222-2222-222222222222', 93, 'What is Kaizen in manufacturing improvement?', 'Japanese philosophy of continuous incremental improvement. Engages all employees in problem-solving. Small improvements compound to significant gains.'),
('22222222-2222-2222-2222-222222222222', 94, 'Explain Visual Factory concept.', 'Making process status visually obvious through charts, indicators, signals. Enables quick problem identification and response. Improves communication and safety.'),
('22222222-2222-2222-2222-222222222222', 95, 'What is Poka-yoke (mistake-proofing)?', 'Design features preventing errors. Physical constraints, color coding, shapes prevent wrong assembly. Reduces defects and inspection requirements.'),
('22222222-2222-2222-2222-222222222222', 96, 'Define Overall Equipment Effectiveness (OEE).', 'Metric combining availability, performance, quality rates. OEE = Availability x Performance x Quality. Target typically 85% or higher.'),
('22222222-2222-2222-2222-222222222222', 97, 'What is Mean Time Between Failures (MTBF)?', 'Average time equipment operates before failure. Higher MTBF indicates better reliability. Used in design and maintenance planning.'),
('22222222-2222-2222-2222-222222222222', 98, 'Define Mean Time To Repair (MTTR).', 'Average time to restore failed equipment. Reduced by spare parts availability and technician training. Important metric for availability calculations.'),
('22222222-2222-2222-2222-222222222222', 99, 'What is availability in manufacturing systems?', 'Percentage of time equipment is operational. Availability = MTBF / (MTBF + MTTR). Target depends on production requirements and system criticality.'),
('22222222-2222-2222-2222-222222222222', 100, 'Explain Safety Integrity Level (SIL) rating.', 'Classification for safety-critical systems. SIL 1 lowest, SIL 4 highest. Specifies required redundancy and testing for safe operation.'),
('22222222-2222-2222-2222-222222222222', 101, 'What is functional safety in industrial systems?', 'Safety achieved through proper functioning of control systems. Requires systematic design and validation. Addresses both random and systematic failures.'),
('22222222-2222-2222-2222-222222222222', 102, 'Define Safety Instrumented Systems (SIS).', 'Systems designed to detect and respond to hazardous conditions. Independent of process control systems. Must achieve specified Safety Integrity Level.'),
('22222222-2222-2222-2222-222222222222', 103, 'What is Permissive interlock in safety systems?', 'System allows operation only when safe conditions exist. Prevents unsafe sequence of operations. Common in machinery with multiple hazards.'),
('22222222-2222-2222-2222-222222222222', 104, 'Explain Emergency Stop (E-stop) function.', 'Immediately stops operation when activated. Must be accessible and reliable. Redundant circuits and hardwired logic ensure safe operation even if control system fails.'),
('22222222-2222-2222-2222-222222222222', 105, 'What is guard interlocking?', 'Prevents equipment operation when guards are open. Protecting operator and equipment. Common on machinery with rotating or moving parts.'),
('22222222-2222-2222-2222-222222222222', 106, 'Define Electrical safety ratings.', 'IP ratings specify protection against dust and water. Voltage ratings specify safe operating ranges. Temperature ratings specify thermal limits.'),
('22222222-2222-2222-2222-222222222222', 107, 'What is Personnel safety factor in automated systems?', 'Design features preventing injury from moving parts or hazardous energy. Guards, interlocks, e-stop, warning devices, training all important. Regular safety audits ensure compliance.'),
('22222222-2222-2222-2222-222222222222', 108, 'Explain Hazard and Operability (HazOp) analysis.', 'Systematic method identifying potential hazards. Team reviews process guidewords: more, less, reverse, other. Identifies consequences and safeguards.'),
('22222222-2222-2222-2222-222222222222', 109, 'What is confined space hazard?', 'Spaces with limited entry/exit and potential for hazardous atmosphere. Common in tanks and vessels. Requires testing, ventilation, and rescue procedures.'),
('22222222-2222-2222-2222-222222222222', 110, 'Define electrical hazards in automation.', 'Risk of electric shock, arc flash, and electrocution. Proper grounding, insulation, lockout-tagout procedures essential. Personal protective equipment required for live work.'),
('22222222-2222-2222-2222-222222222222', 111, 'What is Lockout-Tagout (LOTO) procedure?', 'Process controlling hazardous energy during maintenance. Workers lock and tag energy sources preventing accidental restart. Critical for personnel safety during equipment servicing.'),
('22222222-2222-2222-2222-222222222222', 112, 'Explain arc flash hazard analysis.', 'Identifies potential for electrical arc burns. Requires suitable personal protective equipment. Arc flash labels on equipment indicate hazard severity.'),
('22222222-2222-2222-2222-222222222222', 113, 'What is thermal imaging in maintenance?', 'Uses infrared cameras to detect temperature patterns. Identifies loose connections, insulation problems, bearing failures through heat signature. Non-contact condition monitoring.'),
('22222222-2222-2222-2222-222222222222', 114, 'Define vibration analysis for predictive maintenance.', 'Monitoring vibration signature to detect developing faults. Bearing wear, misalignment, imbalance show characteristic frequency components. FFT analysis identifies fault types.'),
('22222222-2222-2222-2222-222222222222', 115, 'What is oil analysis for equipment condition?', 'Analyzing used oil for wear particles and contaminants. Iron particles indicate bearing/gear wear. Water content indicates seal failure. Guides maintenance decisions.'),
('22222222-2222-2222-2222-222222222222', 116, 'Explain motor current signature analysis (MCSA).', 'Monitoring induction motor current to detect faults. Rotor bar breakage, bearing damage, load imbalance cause characteristic current patterns. Detects faults before failure.'),
('22222222-2222-2222-2222-222222222222', 117, 'What is ultrasonic monitoring?', 'Using ultrasound to detect bearing defects and lubrication problems. Friction generates ultrasonic frequencies at fault locations. Non-destructive early fault detection.'),
('22222222-2222-2222-2222-222222222222', 118, 'Define thermography application in facilities.', 'Thermal imaging for detecting heat loss and electrical problems. Building energy audits identify insulation defects. Electrical inspections find overheating connections.'),
('22222222-2222-2222-2222-222222222222', 119, 'What is drone-based infrastructure inspection?', 'Using unmanned aerial vehicles for hard-to-reach inspections. Wind turbine blades, high structures, solar panels inspected safely. Reduces inspection time and costs.'),
('22222222-2222-2222-2222-222222222222', 120, 'Explain digital transformation in manufacturing.', 'Industry 4.0 integrating IoT, Big Data, and AI in production. Real-time monitoring, predictive analytics, autonomous systems improve efficiency. Requires significant IT infrastructure.'),
('22222222-2222-2222-2222-222222222222', 121, 'What is Internet of Things (IoT) in industrial automation?', 'Networked devices collecting and sharing data. Sensors, controllers, edge computers form distributed system. Enables real-time monitoring and control across facilities.'),
('22222222-2222-2222-2222-222222222222', 122, 'Define Big Data analytics in manufacturing.', 'Collecting and analyzing large volumes of operational data. Identifies trends, patterns, and optimization opportunities. Requires data storage, processing, and visualization infrastructure.'),
('22222222-2222-2222-2222-222222222222', 123, 'What is Artificial Intelligence (AI) application in automation?', 'Machine learning algorithms optimize processes and predict failures. Pattern recognition improves quality control. AI handles complex non-linear relationships human experts may miss.'),
('22222222-2222-2222-2222-222222222222', 124, 'Explain Cloud computing for manufacturing.', 'Hosting manufacturing applications on cloud infrastructure. Enables remote monitoring and control. Provides scalability and reduced IT maintenance burden.'),
('22222222-2222-2222-2222-222222222222', 125, 'What is Cybersecurity in industrial systems?', 'Protecting systems from unauthorized access and attacks. Network segmentation, firewalls, access controls required. Legacy systems require retrofitted security measures.'),
('22222222-2222-2222-2222-222222222222', 126, 'Define Zero Trust Security model.', 'Assumes all network traffic potential threat. Verifies every access request even from internal sources. Provides strong security for connected systems.'),
('22222222-2222-2222-2222-222222222222', 127, 'What is OPC-UA (OLE for Process Control Unified Architecture)?', 'International standard for industrial automation communication. Platform-independent secure data exchange. Enables interoperability across different vendors'' equipment.'),
('22222222-2222-2222-2222-222222222222', 128, 'Explain MQTT protocol for IoT.', 'Lightweight publish-subscribe messaging protocol. Ideal for bandwidth-constrained and unstable networks. Common in IoT applications and edge computing.'),
('22222222-2222-2222-2222-222222222222', 129, 'What is Edge computing in industrial systems?', 'Processing data locally at edge devices rather than cloud. Reduces latency and bandwidth requirements. Essential for real-time control applications.'),
('22222222-2222-2222-2222-222222222222', 130, 'Define digital twin technology.', 'Virtual model of physical process or equipment. Updated with real-time data for monitoring and simulation. Enables testing and optimization before physical changes.'),
('22222222-2222-2222-2222-222222222222', 131, 'What is Augmented Reality (AR) in maintenance?', 'Overlaying digital information on physical equipment. Technicians see maintenance procedures superimposed on real equipment. Improves maintenance efficiency and reduces errors.'),
('22222222-2222-2222-2222-222222222222', 132, 'Explain Virtual Reality (VR) for training.', 'Immersive simulation environments for operator and technician training. Allows safe practice with potentially dangerous equipment. Reduces training time and costs.'),
('22222222-2222-2222-2222-222222222222', 133, 'What is 3D printing (Additive Manufacturing) in production?', 'Building parts layer-by-layer from CAD designs. Reduces waste and enables complex geometries. Suitable for low-volume specialized parts.'),
('22222222-2222-2222-2222-222222222222', 134, 'Define Blockchain in industrial supply chains.', 'Distributed ledger tracking product movement and history. Provides transparency and authenticity verification. Reduces fraud and improves supply chain visibility.'),
('22222222-2222-2222-2222-222222222222', 135, 'What is Quantum computing potential for optimization?', 'Future technology exploiting quantum mechanics for complex calculations. Could solve optimization problems intractable for classical computers. Long development timeline but enormous potential impact.'),
('22222222-2222-2222-2222-222222222222', 136, 'Explain Digital infrastructure requirements for Industry 4.0.', 'Robust network connectivity, reliable servers, secure data centers essential. High availability and disaster recovery required. Significant investment in IT infrastructure needed.'),
('22222222-2222-2222-2222-222222222222', 137, 'What is API (Application Programming Interface) importance?', 'Enables software systems to communicate and share data. Allows integration of different manufacturers'' equipment. Standard APIs reduce integration complexity.'),
('22222222-2222-2222-2222-222222222222', 138, 'Define middleware in manufacturing IT systems.', 'Software layer connecting applications and data sources. Integrates legacy systems with modern platforms. Translates between different protocols and data formats.'),
('22222222-2222-2222-2222-222222222222', 139, 'What is Data governance in enterprises?', 'Policies and procedures controlling data usage and quality. Ensures accuracy, consistency, and security of data. Essential for reliable analytics and decision-making.'),
('22222222-2222-2222-2222-222222222222', 140, 'Explain metadata management.', 'Organizing information about data (who, what, when, where). Enables data discoverability and proper usage. Critical for large databases and data warehouses.'),
('22222222-2222-2222-2222-222222222222', 141, 'What is Master Data Management (MDM)?', 'Centralizing and controlling critical business data. Customer, product, equipment data maintained consistently across systems. Prevents conflicts and improves data quality.'),
('22222222-2222-2222-2222-222222222222', 142, 'Define data pipeline in industrial systems.', 'Process moving data from source through transformation to storage. ETL (Extract, Transform, Load) operations prepare data. Enables data integration from multiple sources.'),
('22222222-2222-2222-2222-222222222222', 143, 'What is NoSQL database application?', 'Non-relational databases handling unstructured data. Document, key-value, time-series databases common. Better for big data and high-velocity streaming data.'),
('22222222-2222-2222-2222-222222222222', 144, 'Explain Time Series database.', 'Specialized database optimizing storage and retrieval of time-stamped data. Efficient compression and fast queries for trend analysis. Ideal for sensor and equipment monitoring data.'),
('22222222-2222-2222-2222-222222222222', 145, 'What is data warehouse purpose?', 'Centralized repository consolidating data from multiple sources. Optimized for analytics and reporting. Structured for easy querying and analysis by business intelligence tools.'),
('22222222-2222-2222-2222-222222222222', 146, 'Define business intelligence (BI) tools.', 'Software visualizing data and creating reports and dashboards. Enables data-driven decision making. Transforms raw data into actionable insights.'),
('22222222-2222-2222-2222-222222222222', 147, 'What is real-time analytics?', 'Processing streaming data immediately upon arrival. Enables immediate response to changing conditions. Requires specialized streaming platforms and algorithms.'),
('22222222-2222-2222-2222-222222222222', 148, 'Explain statistical process control (SPC).', 'Monitoring process using statistical methods. Control charts detect out-of-control conditions. Distinguishes common cause variation from special causes requiring investigation.'),
('22222222-2222-2222-2222-222222222222', 149, 'What is Capability Analysis (Cpk)?', 'Comparing process capability to specification limits. Cpk greater than 1.33 indicates capable process. Guides process improvements and capability predictions.'),
('22222222-2222-2222-2222-222222222222', 150, 'Define defect rate targets in manufacturing.', 'Six Sigma targets 3.4 defects per million. Typical manufacturing targets 0.1-1% defect rates. Depends on product criticality and customer requirements.'),
('22222222-2222-2222-2222-222222222222', 151, 'What is Hypothesis testing in process improvement?', 'Statistical method validating if proposed changes improve process. Compares before/after data using appropriate tests. Controls type I and type II error probabilities.'),
('22222222-2222-2222-2222-222222222222', 152, 'Explain Design of Experiments (DOE).', 'Systematic method investigating effects of multiple factors. Factorial designs efficiently test combinations. Reduces number of experiments needed compared to one-factor-at-a-time.'),
('22222222-2222-2222-2222-222222222222', 153, 'What is Response Surface Methodology (RSM)?', 'Optimization technique using regression to model response surface. Identifies optimal factor settings. More efficient than grid search for continuous variable optimization.'),
('22222222-2222-2222-2222-222222222222', 154, 'Define sensitivity analysis in process design.', 'Determining how output changes with input variations. Identifies critical parameters requiring tight control. Guides specification and tolerance setting.'),
('22222222-2222-2222-2222-222222222222', 155, 'What is Monte Carlo simulation?', 'Probabilistic simulation using random sampling. Evaluates uncertainty impact on outcomes. Useful for complex systems with many variable interactions.'),
('22222222-2222-2222-2222-222222222222', 156, 'Explain simulation validation and verification.', 'Verification ensures simulation correctly implements model. Validation ensures model adequately represents real system. Critical for using simulation results in decision-making.'),
('22222222-2222-2222-2222-222222222222', 157, 'What is agent-based modeling?', 'Simulation representing individual agents with local behaviors. Complex global patterns emerge from interactions. Useful for supply chain, traffic, social system modeling.'),
('22222222-2222-2222-2222-222222222222', 158, 'Define discrete event simulation.', 'Modeling systems as sequence of events changing state. Events occur at specific times. Efficient for systems with long idle periods between events.'),
('22222222-2222-2222-2222-222222222222', 159, 'What is continuous simulation?', 'Differential equations represent system behavior over time. State changes continuously. Appropriate for physical systems like thermal processes and chemical reactors.'),
('22222222-2222-2222-2222-222222222222', 160, 'Explain hybrid simulation.', 'Combining discrete event and continuous simulation. Handles systems with both discrete events and continuous dynamics. More realistic for many industrial processes.'),
('22222222-2222-2222-2222-222222222222', 161, 'What is real-time simulation?', 'Simulation executing at wall-clock speed or faster. Enables hardware-in-loop testing with actual equipment. Validates control algorithms before deploying to real system.'),
('22222222-2222-2222-2222-222222222222', 162, 'Define digital thread in manufacturing.', 'Continuous flow of data throughout product lifecycle. Connects design, manufacturing, operations, and recycling phases. Enables traceability and optimization.'),
('22222222-2222-2222-2222-222222222222', 163, 'What is traceability in manufacturing?', 'Ability to track products and components from raw materials through manufacture. Enables recall of specific batches if defects found. Compliance requirement in many industries.'),
('22222222-2222-2222-2222-222222222222', 164, 'Explain genealogy in process manufacturing.', 'Recording composition and sources of raw materials in batches. Traces complete history of product ingredients. Essential in food, pharmaceutical, and chemical industries.'),
('22222222-2222-2222-2222-222222222222', 165, 'What is Statistical quality control (SQC)?', 'Application of statistics to manufacturing quality. Control charts, capability analysis, sampling plans used. Prevents quality problems rather than detecting after production.'),
('22222222-2222-2222-2222-222222222222', 166, 'Define Acceptance sampling.', 'Inspecting sample rather than entire lot to determine acceptance. Balances inspection cost with risk of accepting bad lots. Uses Acceptable Quality Level (AQL) to define acceptance criteria.'),
('22222222-2222-2222-2222-222222222222', 167, 'What is ISO 9001 requirement for quality?', 'International standard for quality management systems. Requires documented processes, training, and continuous improvement. Certification demonstrates management system effectiveness.'),
('22222222-2222-2222-2222-222222222222', 168, 'Explain ISO 14001 environmental management.', 'Standard for environmental management systems. Addresses resource use, waste, emissions control. Demonstrates environmental responsibility to stakeholders.'),
('22222222-2222-2222-2222-222222222222', 169, 'What is OHSAS 18001 / ISO 45001 for occupational health and safety?', 'Standard for health and safety management. Requires hazard identification and risk control. Protects workers and demonstrates safety commitment.'),
('22222222-2222-2222-2222-222222222222', 170, 'Define ISO 50001 energy management.', 'Standard for energy management systems. Improves energy efficiency and reduces consumption. Cuts operating costs and environmental impact.'),
('22222222-2222-2222-2222-222222222222', 171, 'What is IEC 61508 for functional safety?', 'International standard for safety-critical systems. Specifies design and validation requirements. Widely referenced in machinery and control system safety standards.'),
('22222222-2222-2222-2222-222222222222', 172, 'Explain IEC 61131-3 PLC programming standard.', 'Defines five programming languages for programmable controllers. Ladder Logic, Structured Text, Function Block Diagram, Sequential Function Chart, and Instruction List. Enables portability across vendors.'),
('22222222-2222-2222-2222-222222222222', 173, 'What is IEC 61850 for power systems?', 'Standard for electrical substations communication and control. Defines data models and protocols. Enables interoperability of substation equipment from different vendors.'),
('22222222-2222-2222-2222-222222222222', 174, 'Define NFPA 70 National Electrical Code (NEC).', 'United States electrical installation safety standard. Specifies wiring, grounding, protection requirements. Ensures electrical safety in buildings and facilities.'),
('22222222-2222-2222-2222-222222222222', 175, 'What is ANSI/ISA safety standard role?', 'Instrumentation, Systems, and Automation Society standards for process safety. Addresses design, installation, operation of safety-critical systems. Widely adopted in process industries.'),
('22222222-2222-2222-2222-222222222222', 176, 'Explain ATEX directive for hazardous areas.', 'European regulation for equipment in explosive atmospheres. Classifications for gas, vapor, dust hazards. Equipment certifications demonstrate compliance for hazardous location use.'),
('22222222-2222-2222-2222-222222222222', 177, 'What is North American Class Division system for hazardous locations?', 'NEC classification for areas with flammable gases or dusts. Class I gas, Class II dust. Divisions indicate likelihood of hazardous condition. Equipment ratings match classified location.'),
('22222222-2222-2222-2222-222222222222', 178, 'Define Ingress Protection (IP) rating system.', 'Numbers specify protection against solids and liquids. First digit (0-6) for solids, second (0-9) for liquids. Higher numbers indicate better protection.'),
('22222222-2222-2222-2222-222222222222', 179, 'What is NEMA enclosure rating system?', 'North American standard classifying enclosure protection levels. NEMA 4 suitable for wet locations. NEMA 7 for hazardous locations. Guides enclosure selection for environment.'),
('22222222-2222-2222-2222-222222222222', 180, 'Explain EMC (Electromagnetic Compatibility) requirements.', 'Products must not emit excessive electromagnetic interference. Must tolerate received interference. Testing demonstrates compliance with emission and immunity standards.'),
('22222222-2222-2222-2222-222222222222', 181, 'What is RoHS (Restriction of Hazardous Substances)?', 'European directive restricting lead, mercury, cadmium and other substances. Reduces environmental impact and health hazards. Required for equipment sold in EU.'),
('22222222-2222-2222-2222-222222222222', 182, 'Define WEEE (Waste Electrical and Electronic Equipment) directive.', 'Ensures proper recycling of discarded electrical equipment. Manufacturers responsible for collection and recycling. Reduces landfill waste and recovers valuable materials.'),
('22222222-2222-2222-2222-222222222222', 183, 'What is lifecycle assessment (LCA)?', 'Evaluating environmental impact from extraction through disposal. Identifies hotspots for improvement. Informs sustainable design decisions.'),
('22222222-2222-2222-2222-222222222222', 184, 'Explain circular economy principles.', 'Design for reuse, repair, remanufacturing, and recycling. Reduces resource consumption and waste. Requires product design and business model changes.'),
('22222222-2222-2222-2222-222222222222', 185, 'What is take-back program responsibility?', 'Manufacturers responsible for end-of-life product management. Reduces environmental impact and recovers materials. Builds customer loyalty and regulatory compliance.'),
('22222222-2222-2222-2222-222222222222', 186, 'Define Industrial Symbiosis.', 'Waste or byproduct from one process becomes input for another. Reduces overall resource consumption. Creates economic and environmental benefits through cooperation.'),
('22222222-2222-2222-2222-222222222222', 187, 'What is dematerialization in manufacturing?', 'Providing services with fewer materials and energy. Digital products replace physical. Reduces environmental impact while meeting customer needs.'),
('22222222-2222-2222-2222-222222222222', 188, 'Explain carbon footprint reduction strategies.', 'Energy efficiency improvements reduce operational emissions. Renewable energy sources replace fossil fuels. Logistics optimization reduces transportation emissions.'),
('22222222-2222-2222-2222-222222222222', 189, 'What is Corporate Social Responsibility (CSR)?', 'Business commitment to ethical and sustainable practices. Beyond compliance includes community support and environmental stewardship. Builds reputation and stakeholder trust.'),
('22222222-2222-2222-2222-222222222222', 190, 'Define supply chain sustainability.', 'Ensuring suppliers meet environmental and social standards. Audits verify compliance. Reduces risks from supplier violations and improves overall supply chain responsibility.'),
('22222222-2222-2222-2222-222222222222', 191, 'What is conflict minerals problem?', 'Mining practices in war zones fund armed groups. Electronics manufacturers must verify mineral sources. Traceability requirements in regulations like Dodd-Frank Act.'),
('22222222-2222-2222-2222-222222222222', 192, 'Explain labor standards in global supply chains.', 'Suppliers required to meet fair wages and safe working conditions. Audits verify compliance. Consumer awareness drives demand for ethical manufacturing.'),
('22222222-2222-2222-2222-222222222222', 193, 'What is technology transfer in developing countries?', 'Sharing advanced manufacturing techniques and knowledge with emerging economies. Improves productivity and competitiveness globally. Reduces technology gap.');
